import React from "react";
import { Link } from "react-router-dom";
import data from "../data/logement.json";
import Card from "../components/Card";
import "./css/style.css"; // Assurez-vous que les styles appropriés sont importés

const Home = () => {
  return (
    <>
      <header className="_Header">
        <nav>
          <ul>
            <li><Link to="/">Accueil</Link></li>
            <li><Link to="/about">A Propos</Link></li>
          </ul>
        </nav>
      </header>
      <main className="_Body">
        <section className="_Section 1">
          <div className="Mask Group">
            <img src="background_image_url" alt="Background" />
            <h1>Chez vous, partout et ailleurs</h1>
          </div>
        </section>
        <section className="Gallery">
          <div className="toto">
            {data.map((item, index) => (
              <Link key={index} to={`/logement/${item.id}`}>
                <Card title={item.title} image={item.cover} />
              </Link>
            ))}
          </div>
        </section>
      </main>
      <footer className="_Footer">
        <p>© 2020 Kasa. All rights reserved</p>
      </footer>
    </>
  );
};

export default Home;
